import { default as zrender,createZrender } from './zrender-helper.js'
import MText from './poster/WxPainter/MText.class.js'
export default class Element{
  constructor(json){
    let defaultOptions = {
      //全局的位置
      w : 0,
      h : 0,
      mode : 0, //基于左上角的定位0，基于行模型定位1
      row : 0, //是否启用行包围
      position : [0,0], //基于父集的定位
      //父集的位置
      px : 0,
      py : 0,
      mx : 0,
      my : 0,
      css : {},
      childs : []
    }
    Object.assign(this,defaultOptions,json)
    this.build(this);
  }
  build(element){
    //这里要不要算子元素
    let childs = element.childs || [];
    let ch = 0;
    let myh = element.h;
    //相对于父集的偏移
    let [rx = 0,ry = 0] = element.position || [];
    //父集的位置
    let { px = 0,py = 0 } = element;
    let { mx = 0,my = 0 } = element;
    //相对于整个画布的坐标，如果是mode:1的布局计算不同
    let x,y;
    x = px + rx + mx;
    y = py + ry + my;

    element.rx = rx;
    element.ry = ry;
    element.x = x;
    element.y = y;

    let mode1x = 0;
    let mode1y = 0;

    let maxH = 0;
    for(var i=0;i<childs.length;i++){
      let child = childs[i];
      let mode = child.mode;
      if(mode == 1){
        child.px = x;
        child.py = y;
        child.mx = mode1x;
        child.my = mode1y;
      }else{
        child.px = x;
        child.py = y;
      }
      //先算位置再初始化
      child = childs[i] = new Element(child)
      //给下一个mode 1的元素定位父级框，累加自己的高度 + 自己的偏移量
      if(mode == 1){
        ch += child.h + child.ry;
        //mode1y 跟 ch不同
        mode1y += child.h + child.ry;
      }

      let childEnd = child.ry + child.h;
      maxH = Math.max(childEnd);
    }

    //绝对定位元素
    if(myh){
      element.h = myh;
    }else{
      element.h = ch;
    }

    if(element.row == 1){
      element.h = maxH;
    }
    if(element.debug){
    }
    this.toCSS(element);
  }
  toCSS(element){
    let { x,y,w,h,css } = element;
    element.css = Object.assign({},css,{
      width : w + 'px',
      height : h + 'px',
      border : '1px solid #000',
      position : 'fixed',
      left : `${ x }px`,
      top : `${ y }px`,
    });
  }
}

export class ElementUIWx{
  constructor(options){
    this.options = options;
    this.elem = new Element(options.json);
    let { w,h } = this.elem;
    this.main = createZrender(options.canvasId,w,h,this.options.context)
  }
  render(){
    let { elem } = this;
    return this.createElement(elem).then(res => this.main.add(res));
  }
  getImageInfo(url){
    return ElementUIWx.getImageInfo(url);
  }
  static getImageInfo(url){
    return new Promise(resolve => {
      uni.getImageInfo({
        src : url,
        success : (res) => {
          resolve(res.path)
        },
        fail : res => {
          resolve(0);
        }
      })
    })
  }
  drawImage(element){
    let url = element.url;
    if(this.options.proxy){
      url = this.options.proxy(url);
    }
    return this.getImageInfo(url).then(image => {
      if(image){
        let w = element.w;
        let h = element.h;
        let obj = {
          shape : {
            width : w,
            height : h,
          },
          //position : [element.x,element.y],
          style :{
            //fill : element.css.background,
            width : w,
            height : h,
            image : image,
            stroke : '#000',
            lineWidth : 1,
          },
        }

        obj = this.mergeConfig(obj,element);
        console.log('obj',obj);
        let rect = new zrender.Image(obj)
        element.drawCallback && element.drawCallback(rect);
        return rect;
      }else{
        //element.drawCallback && element.drawCallback(image);
      }
    })
  }
  mergeConfig(obj,element){
    let { ext } = element;
    for(var k in ext){
      if(typeof ext[k] === 'object'){
        obj[k] = Object.assign({},obj[k] || {},ext[k] || {});
      }else{
        obj[k] = ext[k];
      }
    }
    element.callback && element.callback(obj);
    return obj;
  }
  drawRect(element){

    let obj = {
      shape : {
        width : element.w,
        height : element.h,
      },
      //position : [element.x,element.y],
      style : {
        fill : element.css.background,
      }
    }
    obj = this.mergeConfig(obj,element)

    console.log('obj',obj);
    let rect = new zrender.Rect(obj)
    element.drawCallback && element.drawCallback(rect);
    return rect;
  }
  drawText(element){
    let obj = {
      shape : {
        width : element.w,
        height : element.h,
      },
      //position : [element.x,element.y],
      style : {
        text : element.css.text,
        font : element.css.font,
        fill : element.css.background,
        textAlign : 'left',
        textPosition : 'left',
      }
    }
    obj = this.mergeConfig(obj,element);
    let text = new zrender.Rect(obj)
    element.drawCallback && element.drawCallback(text);
    return text;
  }
  createElement(element){
    let group = new zrender.Group({
      position : [element.rx + element.mx,element.ry + element.my]
    });
    let p = Promise.resolve();
    if(element.type == 'image'){
      p = this.drawImage(element).then(res => group.add(res));
    }
    if(element.type == 'rect'){
      let rect = this.drawRect(element);
      group.add(rect);
    }
    if(element.type == 'text'){
      let text = this.drawText(element);
      group.add(text);
    }
    return p.then(res => {
      let ps = [];
      element.childs.forEach(child => {
        ps.push(this.createElement(child).then(res => {
          group.add(res);
        }));
      });
      return Promise.all(ps);
    })
    .then(res => {
      if(element.groupCallback){
        return element.groupCallback(group);
      }else{
        return group;
      }
    });
  }
  output(){
    let { elem } = this;
    return new Promise(resolve => {
      uni.canvasToTempFilePath({
        canvasId: this.options.canvasId,
        fileType : 'png',
        destWidth : elem.w,
        destHeight : elem.h,
        success: (res) => {
          let { tempFilePath } = res;
          resolve(res);
        },
        fail: function (error) {
          console.log(error);
        },
      },this.options.context);
    })
  }
  static splitTextLines(canvasId,w,text,font,context,skips){
    let main = createZrender(canvasId,100,100,context)
    let ctx = zrender.util.getContext();
    let word = text;
    let mtxt = new MText(word,{
      font : font,
    },ctx);
    let lines = mtxt.convert(w,skips);
    return lines;
  }
}

//渲染测试用的
export class ElementUI{
  constructor(){
  
  }
  static render(options){
    this.options = options;
    this.createElement(this.options.element);
  }

  static createElement(element){
    let zrender = this.options.zrender;
    let MText = this.options.MText;
    let main = this.options.main;
    element.type = element.type || 'rect';
    if(element.type == 'rect'){
      let rect = new zrender.Rect({
        shape : {
          width : element.w,
          height : element.h,
        },
        position : [element.x,element.y],
        style : {
          fill : element.css.background,
          stroke : '#000',
          lineWidth : 1,
        }
      })
      main.add(rect);
    }
    if(element.type == 'text'){
      let tmp = zrender.util.createCanvas();
      let ctx = tmp.getContext('2d');
      let word = element.css.text;
      let textWidth = element.css.textWidth;
      let font = element.css.font;
      let lines = this.convertText({
        word,
        ctx,
        font,
        width : textWidth,
      })
      let text = new zrender.Text({
        shape : {
          width : element.w,
          height : element.h,
        },
        position : [element.x,element.y],
        style : {
          text : lines.join('\n'),
          font : element.css.font,
          stroke : '#000',
          lineWidth : 1,
        }
      })
      main.add(text);
    }

    element.childs.forEach(child => {
      this.createElement(child);
    });
  }
  static convertText(options){
    let { word,font,width,ctx } = options
    let MText = this.options.MText;
    let mtxt = new MText(word,{
      font
    },ctx);
    let w = width || 100;
    let lines = mtxt.convert(w);
    return lines;
  }
  
}

export { zrender,createZrender }
