class MText{
  constructor(text,option,ctx){
    Object.assign(this,{
      text,
      option,
      ctx
    })
  }
  convert(width,skips = []){
    this.ctx.save();
    const { option } = this;
    const { fontSize,fontWeight='normal',fontFamily='',font = '' } = option;
    if(!font){
      font = `${fontWeight} ${fontSize} ${fontFamily ? fontFamily : 'sans-serif'}`;
    }
    this.ctx.font = font;
    this.ctx.setFontSize(parseInt(fontSize));
    for(let key in option){
      this.ctx[key]= option[key];
    }
    const { text } = this;
    let widthArray = [];
    let charWidth = 0;
    for(var i = 0; i < text.length;i++){
      let c = text[i];
      let item = skips.filter(res => {
        return res.index == i;
      })
      if(item.length){
        charWidth = item[0].w;
      }else{
        charWidth = this._measureWidth(c);
      }
      widthArray.push({
        index : i,
        width : charWidth,
        text : c
      });
    }
    //console.log(widthArray);
    this.ctx.restore();
    return this._splitTextToLines(width,widthArray,text);
  }
  _splitTextToLines(width,widthArray,text){
    console.log(width,widthArray,text);
    let lineWidth = 0;
    let lineCharNum = 0;
    let lines = [];
    let line = [];
    if(widthArray.length == 0) return;
    let lastK = 0;

    widthArray.forEach((v,k) => {
      //console.log(v,k);
      if(/\n/.test(v.text)){
        lines.push(line.join(''));
        line = [];
        lineWidth = 0;
      }else {
        lineWidth += v.width;
        if(lineWidth > width){
          if(this.testEndSymbol(v.text) && k - lastK > 1){
            lastK = k;
            line.push(v.text);
            //这里自动换行跟手动换行可能冲突
            if(widthArray.length > k + 1 && widthArray[k+1].text == '\n'){
            }else{
              lines.push(line.join(''))
              line = [];
              lineWidth = 0;
            }
          }else{
            lines.push(line.join(''));
            line = [v.text];
            lineWidth = v.width;
          }
        }else{
          line.push(v.text);
        }
      }
    });
    //console.log(line);
    lines.push(line.join(''));
    return lines;
  }
  testEndSymbol(text){
    var regExp = /^[\·\~\！\@\#\￥\%\……\&\*\（\）\——\-\+\=\【\】\{\}\、\|\；\‘\’\：\“\”\《\》\？\，\。\、\`\~\!\#\$\%\^\&\*\(\)\_\[\]{\}\\\|\;\'\'\:\"\"\,\.\/\<\>\?]+$/;
    return regExp.test(text);
  }
  _measureWidth(c){
    //const { option } = this;
    //const { width } = new zrender.Text({
      //style : {
        //text : c,
        //font : option.font || ''
      //}
    //}).getBoundingRect();
    //return width;
    return this.ctx.measureText(c).width;
  }
  measureTextWidth(){
    const { option,ctx,text } = this;
    const { fontSize,fontWeight='normal',fontFamily='' } = option;
    const font = `normal ${fontWeight} ${fontSize} ${fontFamily ? fontFamily : 'sans-serif'}`;
    ctx.save();
    ctx.font = font;
    let width = ctx.measureText(text).width
    ctx.restore();
    return width;
  }
  static measureTextWidth(text,ctx,option){
    const { fontSize,fontWeight='normal',fontFamily='' } = option;
    const font = `normal ${fontWeight} ${fontSize} ${fontFamily ? fontFamily : 'sans-serif'}`;
    ctx.font = font;
    ctx.setFontSize(parseInt(fontSize));
    return ctx.measureText(text).width
  }
}
export default MText
